TreasureChallengeConfig = {}
TreasureChallengeConfig.Settings = {}
TreasureChallengeConfig.times = "0"

local function isNotTimeOut(starTime, endTime)
    ---秘宝挑战是否未过期（未开始也返回true）
    local now = os.time(os.date("*t"))
    if now < endTime then
        return true
    end
end

local function isInTimeRange(starTime, endTime)
    ---秘宝挑战是否正在进行中
    local nowNum = os.time(os.date("*t"))
    if nowNum >= starTime and nowNum < endTime then
        return true
    end
    return false
end

local function init()
    local config = FileUtil.getConfigFromCsv("setting/TreasureChallenge.csv")
    for _, item in pairs(config) do
        local data = {}
        data.times = tostring(item.times) or "1"
        local date = StringUtil.split(item.startDate, "-", false, true)
        data.startDate = DateUtil.date2BeiJingTime({ day = date[3], month = date[2], year = date[1], hour = date[4], min = date[5], sec = date[6] })
        date = StringUtil.split(item.endDate, "-", false, true)
        data.endDate = DateUtil.date2BeiJingTime({ day = date[3], month = date[2], year = date[1], hour = date[4], min = date[5], sec = date[6] })
        data.title = tostring(item.title) or ""
        data.atlas = tostring(item.atlas) or ""
        if isNotTimeOut(data.startDate, data.endDate) or isClient then
            TreasureChallengeConfig.Settings[data.times] = data
        end
    end

    config = FileUtil.getConfigFromCsv("setting/TreasureChallengeReward.csv")
    for _, item in pairs(config) do
        if TreasureChallengeConfig.Settings[tostring(item.times)] ~= nil then
            local data = {
                rewardId = tonumber(item.id) or 0,
                itemId = tonumber(item.itemId) or 0,
                itemType = tonumber(item.itemType) or 0,
                itemNum = tonumber(item.itemNum) or 0,
                dressTab = tonumber(item.dressTab) or 1,
                type = tonumber(item.type) or 0,
                isRecommend = tonumber(item.isRecommend) or 1,
                scale1 = tonumber(item.scale1) or 1,
                offset1 = tonumber(item.offset1) or 0,
                scale2 = tonumber(item.scale2) or 1,
                offset2 = tonumber(item.offset2) or 0,
                needPoints = tonumber(item.needPoints) or 0,
                taskGroupId = tonumber(item.taskGroupId) or 0,
                name = tostring(item.name) or "",
                image = tostring(item.image) or "",
                introduce = tostring(item.introduce) or "",
                actorName = tostring(item.ActorName) or "",
                uiSkillName = tostring(item.uiSkillName) or "",
                minDays = tostring(item.minDays) or "",
                seq = tonumber(item.seq) or 1,
            }

            TreasureChallengeConfig.Settings[tostring(item.times)].rewardList = TreasureChallengeConfig.Settings[tostring(item.times)].rewardList or {}
            table.insert(TreasureChallengeConfig.Settings[tostring(item.times)].rewardList, data)
        end
    end

    if not isClient then
        LuaTimer:schedule(function()
            for _, settings in pairs(TreasureChallengeConfig.Settings) do
                for _, data in pairs(settings.rewardList) do
                    if data.itemType == 2 then
                        local isReal, temRuneId = TreasureChallengeConfig:isRealRuneId(data.itemId)
                        if isReal then
                            data.itemId = temRuneId
                        end
                    end
                end
            end
        end, 0)
    end
end

init()

function TreasureChallengeConfig:getCurrentChallenge()
    for _, setting in pairs(self.Settings) do
        if isInTimeRange(setting.startDate, setting.endDate) then
            self.times = setting.times
            return setting
        end
    end
    return nil
end

function TreasureChallengeConfig:getChallengeByTimes(times)
    for _, setting in pairs(self.Settings) do
        if setting.times == times then
            self.times = setting.times
            return setting
        end
    end
    return nil
end

function TreasureChallengeConfig:getRealRune(temRuneId)
    for _, mapping in pairs(GameConfig.runeMapping) do
        if mapping.temRuneId == temRuneId then
            return mapping.realRuneId
        end
    end
    return temRuneId
end

function TreasureChallengeConfig:isRealRuneId(RuneId)
    for _, mapping in pairs(GameConfig.runeMapping) do
        if mapping.realRuneId == RuneId then
            return true, mapping.temRuneId
        end
    end
    return false, RuneId
end

return TreasureChallengeConfig


